// Evening check-in: scan the vault for ACTIVE items (projects + learning topics),
// write a roster + `awaiting` flag the two-way assistant reads, and return the
// prompt text. When the user replies in plain language, the assistant maps it to
// this roster and logs `touch` actions - so the staleness clock stays honest
// without anyone remembering /touch commands.
const fs = require('fs');
const path = require('path');
const VAULT = '/data/vault';
const INBOX = '/data/inbox';
const SKIP = new Set(['.git', '.obsidian', '.trash', 'node_modules', '.stfolder']);

function walk(dir, out) {
  let entries;
  try { entries = fs.readdirSync(dir, { withFileTypes: true }); } catch (e) { return; }
  for (const e of entries) {
    const full = path.join(dir, e.name);
    if (e.isDirectory()) { if (!SKIP.has(e.name)) walk(full, out); }
    else if (e.isFile() && e.name.toLowerCase().endsWith('.md')) {
      try { out.push({ file: path.relative(VAULT, full), raw: fs.readFileSync(full, 'utf8') }); } catch (e2) {}
    }
  }
}

function frontmatter(text) {
  const o = {};
  const m = text.match(/^﻿?---\s*\r?\n([\s\S]*?)\r?\n---/);
  if (!m) return o;
  for (const line of m[1].split(/\r?\n/)) {
    const t = line.trim();
    if (!t || t.startsWith('#')) continue;
    const i = line.indexOf(':');
    if (i === -1) continue;
    const v = line.slice(i + 1).trim().replace(/\s+#.*$/, '').replace(/^["']|["']$/g, '');
    o[line.slice(0, i).trim()] = v;
  }
  return o;
}

const files = [];
walk(VAULT, files);
const titles = [];
for (const f of files) {
  if (typeof f.raw !== 'string') continue;
  const fm = frontmatter(f.raw);
  const type = String(fm.type || '').toLowerCase();
  if (String(fm.status || '').toLowerCase() === 'done') continue;
  if (type !== 'project' && type !== 'learning') continue;
  const fallback = String(f.file || '').replace(/\.md$/i, '').split('/').pop();
  if (fm.title || fallback) titles.push(fm.title || fallback);
}
const roster = Array.from(new Set(titles.filter(Boolean))).slice(0, 60);

// Persist the roster + awaiting flag for the assistant's check-in branch.
try {
  fs.mkdirSync(INBOX, { recursive: true });
  fs.writeFileSync(path.join(INBOX, '.tg_checkin.json'),
    JSON.stringify({ ts: new Date().toISOString(), awaiting: true, projects: roster }));
} catch (e) { /* if the inbox is read-only the prompt still goes out */ }

const esc = (s) => String(s).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const sample = roster.slice(0, 8).map(esc).join(', ');
const text = '🌙 <b>Evening check-in</b>\nWhat did you move forward today? Reply in a sentence or two and I’ll update your projects.'
  + (sample ? '\n\n<i>Active: ' + sample + (roster.length > 8 ? ' …' : '') + '</i>' : '');

return [{ json: { text, count: roster.length } }];
